import {useReducer} from "react";
import {useSelector} from "react-redux";

import {IconAdd, IconOptions} from "./features/icons/icons.js";

import TodoItem from "./features/todos/TodoItem.js";
import ModalButton from "./features/ModalButton.js";
import ChangeThemeButton from "./features/changeThemeButton.js";
import FilterConfig from "./features/filter/FilterConfig.js";
import AddTodoItem from "./features/todos/AddTodoItem.js";
import EditTodoItem from "./features/todos/EditTodoItem.js";
import "./App.scss";

const selectTodosIDs = (state) => {
    const filters = state.filters;
    const todos = state.todos;
    let statusFilter;
    if (filters.status === "Active") {
        statusFilter = Object.keys(todos).filter((key) => !todos[key].completed);
    } else if (filters.status === "Completed") {
        statusFilter = Object.keys(todos).filter((key) => todos[key].completed);
    } else {
        statusFilter = Object.keys(todos);
    }
    if (filters.colors.length > 0) {
        statusFilter = statusFilter.filter((key) => filters.colors.includes(todos[key].color));
    }
    if (filters.tags.length > 0) {
        statusFilter = statusFilter.filter((key) => {
            for (let tag of filters.tags) {
                if (todos[key].tags.includes(tag)) return true;
            }
            return false;
        });
    }
    return statusFilter.reverse();
};

const initModal = { value: false, type: "", id: "" };

const modalReducer = (state = initModal, action) => {
    switch (action.type) {
        case "modal/filterConfig": return { value: true, type: "FILTER_CONFIG", id: "" };
        case "modal/addTodo": return { value: true, type: "ADD_TODO", id: "" };
        case "modal/editTodo": return { value: true, type: "EDIT_TODO", id: action.payload };
        case "modal/close": return initModal;
        default: return state;
    }
};

function AsideContent({type, closeModal, active, id}) {
    switch (type) {
        case "FILTER_CONFIG": return <FilterConfig active={active} closeModal={closeModal} />;
        case "ADD_TODO": return  <AddTodoItem closeModal={closeModal} />;
        case "EDIT_TODO": return  <EditTodoItem closeModal={closeModal} id={id} />;
        default: return null;
    }
}

function App() {
    const [modal, setModal] = useReducer(modalReducer, initModal);
    const todosIds = useSelector(selectTodosIDs);

    const closeModal = () => { setModal({ type: "modal/close" }); };
    const filterConfigModalOnClick = () => { setModal({type: "modal/filterConfig"}); };
    const addTodoModalOnClick = () => { setModal({type: "modal/addTodo"}); };

    const TodoItems = todosIds.map((id) => (
        <TodoItem key={id} id={id} setModal={setModal} />
    ));

    return (
        <>
        <header className="p-3 flex-row align-c justify-sb">
            <ModalButton
                onClick={filterConfigModalOnClick}
                className="config br-2 p-1"
            >
                <IconOptions />
            </ModalButton>
            <ModalButton
                onClick={addTodoModalOnClick}
                className="add-todo br-2 p-1"
            >
                <h1 className="flex-row align-c">
                    <IconAdd title="Add Todo"/>
                </h1>
            </ModalButton>
            <ChangeThemeButton />
        </header>
        {modal.value && (
            <aside className="flex-column align-c justify-c" >
                <AsideContent 
                    type={modal.type} 
                    closeModal={closeModal} 
                    active={modal.value} 
                    id={modal.id}
                />
            </aside>
        )}
        <main className="todos-container flex-grow-1 p-2">
            {TodoItems}
        </main>
        <footer>
            <p className="fs-text-s text-center">
            by{" "}
                <a
                    className="fs-text-s text-center"
                    href="https://github.com/AxelArielSaravia/"
                    target="_blank"
                    rel="noreferrer noopener"
                >
                    Axel Ariel Saravia
                </a>
            </p>
        </footer>
        </>
    );
}

export default App;
